    // Async command methods

    /// <summary>Send SetpointRaiseLower command (0x0000).</summary>
    public Task<InvokeResponse> SetpointRaiseLowerAsync(
        SetpointRaiseLowerModeEnum mode,
        sbyte amount,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0000, tlv =>
        {
            tlv.AddUInt8(0, (byte)mode);
            tlv.AddInt8(1, amount);
        }, ct);

    /// <summary>Send SetWeeklySchedule command (0x0001).</summary>
    public Task<InvokeResponse> SetWeeklyScheduleAsync(
        byte numberOfTransitionsForSequence,
        ScheduleDayOfWeekBitmap dayOfWeekForSequence,
        ScheduleModeBitmap modeForSequence,
        WeeklyScheduleTransitionStruct[] transitions,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0001, tlv =>
        {
            tlv.AddUInt8(0, numberOfTransitionsForSequence);
            tlv.AddUInt8(1, (byte)dayOfWeekForSequence);
            tlv.AddUInt8(2, (byte)modeForSequence);
            if (transitions != null) { tlv.AddArray(3); foreach (var item in transitions) { WriteWeeklyScheduleTransitionStruct(tlv, item); } tlv.EndContainer(); }
        }, ct);

    /// <summary>Send GetWeeklySchedule command (0x0002).</summary>
    public Task<InvokeResponse> GetWeeklyScheduleAsync(
        ScheduleDayOfWeekBitmap daysToReturn,
        ScheduleModeBitmap modeToReturn,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0002, tlv =>
        {
            tlv.AddUInt8(0, (byte)daysToReturn);
            tlv.AddUInt8(1, (byte)modeToReturn);
        }, ct);

    /// <summary>Send ClearWeeklySchedule command (0x0003).</summary>
    public Task<InvokeResponse> ClearWeeklyScheduleAsync(CancellationToken ct = default)
        => InvokeCommandAsync(0x0003, ct: ct);

    /// <summary>Send SetActiveScheduleRequest command (0x0005).</summary>
    public Task<InvokeResponse> SetActiveScheduleRequestAsync(
        byte[] scheduleHandle,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0005, tlv => { tlv.AddOctetString(0, scheduleHandle); }, ct);

    /// <summary>Send SetActivePresetRequest command (0x0006).</summary>
    public Task<InvokeResponse> SetActivePresetRequestAsync(
        byte[] presetHandle,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0006, tlv => { tlv.AddOctetString(0, presetHandle); }, ct);

    /// <summary>Send AddThermostatSuggestion command (0x0007).</summary>
    public Task<InvokeResponse> AddThermostatSuggestionAsync(
        byte[] presetHandle,
        uint? effectiveTime,
        ushort expirationInMinutes,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0007, tlv =>
        {
            tlv.AddOctetString(0, presetHandle);
            if (effectiveTime != null) tlv.AddUInt32(1, effectiveTime.Value);
            tlv.AddUInt16(2, expirationInMinutes);
        }, ct);

    /// <summary>Send RemoveThermostatSuggestion command (0x0008).</summary>
    public Task<InvokeResponse> RemoveThermostatSuggestionAsync(
        byte uniqueID,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x0008, tlv => { tlv.AddUInt8(0, uniqueID); }, ct);

    /// <summary>Send AtomicRequest command (0x00FE).</summary>
    public Task<InvokeResponse> AtomicRequestAsync(
        AtomicRequestTypeEnum requestType,
        uint[] attributeRequests,
        ushort? timeout = default,
        CancellationToken ct = default)
        => InvokeCommandAsync(0x00FE, tlv =>
        {
            tlv.AddUInt8(0, (byte)requestType);
            if (attributeRequests != null) { tlv.AddArray(0); foreach (var item in attributeRequests) { tlv.AddUInt32(item); } tlv.EndContainer(); }
            if (timeout != null) tlv.AddUInt16(0, timeout.Value);
        }, ct);

